INSERT INTO public.aulas (id, modulo_id, titulo, slug, descricao, video_url, duracao_segundos, ordem, created_at, updated_at, tipo_conteudo, questionario_id, recurso_id, liberacao_dias, is_gratis) VALUES ('e006eb57-9049-4a7f-a656-6a761a0148ff', NULL, 'Autoconhecimento e Autoavaliação', 'rgc-ferramenta-autoavaliacao', 'Ferramenta de autoconhecimento e autoavaliação para o Gestor Comercial identificar seus gaps e oportunidades de desenvolvimento considerando os aspectos relacionados à Liderança e Desenvolvimento de Pessoas e Negócios dentro do modelo Managing & Coaching', '', 1, 0, '2026-04-19T06:59:05.21768+00:00', '2026-04-19T06:59:05.21768+00:00', 'ferramenta', NULL, '8f5dec27-5940-4643-aa1e-9ea91d4df8f7', 0, false) ON CONFLICT DO NOTHING;
INSERT INTO public.aulas (id, modulo_id, titulo, slug, descricao, video_url, duracao_segundos, ordem, created_at, updated_at, tipo_conteudo, questionario_id, recurso_id, liberacao_dias, is_gratis) VALUES ('0fc0ac0e-fd00-484a-8ba8-6d8f5c031f57', NULL, 'Avaliação Gap Analysis e PDI', 'avaliacao-gap-analysis-e-pdi', 'Ferramenta é uma avaliação estruturada que o gestor realiza sobre cada pessoa da equipe, com foco na identificação das lacunas de competências e apresenta a possiblidade de elaborar PDIs individuais. ', '', 1, 0, '2026-04-22T15:55:00.626301+00:00', '2026-04-22T15:55:00.626301+00:00', 'ferramenta', NULL, '66eb7d47-c1de-449f-9633-90c5421727e4', 0, false) ON CONFLICT DO NOTHING;
INSERT INTO public.aulas (id, modulo_id, titulo, slug, descricao, video_url, duracao_segundos, ordem, created_at, updated_at, tipo_conteudo, questionario_id, recurso_id, liberacao_dias, is_gratis) VALUES ('c1110641-3408-4768-a2a1-5a6cf82e0935', NULL, 'Avaliação Metas e OKRs com Planos de Ação', 'meta-okr-plano', 'O que é Ferramenta de avaliação interativa que diagnostica a maturidade do gestor e da equipe no processo de Metas / OKRs Comerciais — cobrindo desde a definição e comunicação das metas até o acompanhamento e os planos de ação que sustentam os resultados.
INSERT INTO public.aulas (id, modulo_id, titulo, slug, descricao, video_url, duracao_segundos, ordem, created_at, updated_at, tipo_conteudo, questionario_id, recurso_id, liberacao_dias, is_gratis) VALUES ('017f1d96-7a71-4b36-863c-60b280f905ff', NULL, 'Autoavaliação do Gestor', 'autoavaliacao-do-gestor', 'Capturar a autopercepção do gestor sobre seu desempenho nas dimensões de Managing (gestão de rotina, processos e resultados) e Coaching (desenvolvimento de pessoas). ', '', 1, 0, '2026-04-21T10:35:59.021631+00:00', '2026-04-21T10:35:59.021631+00:00', 'ferramenta', NULL, '74af1be2-39c1-4fc6-a3b2-3e2b3e0bf607', 0, false) ON CONFLICT DO NOTHING;
INSERT INTO public.aulas (id, modulo_id, titulo, slug, descricao, video_url, duracao_segundos, ordem, created_at, updated_at, tipo_conteudo, questionario_id, recurso_id, liberacao_dias, is_gratis) VALUES ('9749bdbc-4160-4400-8020-bcd76e26bfa8', NULL, 'Análise Influenciadores de Desempenho e Plano', 'influenciadores-plano', 'Ela permite ao gestor comercial mapear, de forma sistemática e visual, o nível atual de desenvolvimento dos 17 Fatores Influenciadores de Desempenho — as alavancas que determinam se uma operação comercial entrega resultados previsíveis ou depende da sorte e do esforço individual.', '', 1, 0, '2026-04-22T17:12:45.724275+00:00', '2026-04-22T17:12:45.724275+00:00', 'ferramenta', NULL, 'b8cf8a4f-b559-4d49-9f82-b21d93ac0737', 0, false) ON CONFLICT DO NOTHING;
